/**
 * mechsense-api  v1.0.0
 * MechSense 計算 REST API サーバー
 * 仕様: MECHSENSE_API_SPEC.md v1.2.0
 */

'use strict';

const express  = require('express');
const MechSense = require('../mechsense-core.js');

const app  = express();
const PORT = process.env.PORT || 3000;

app.use(express.json());

// CORS（開発時のみ全許可、本番はオリジン制限）
app.use((req, res, next) => {
  res.setHeader('Access-Control-Allow-Origin',  process.env.CORS_ORIGIN || '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  if (req.method === 'OPTIONS') return res.sendStatus(204);
  next();
});

// ─── ヘルパー ────────────────────────────────────────────

function ok(res, module, result) {
  return res.json({ ok: true, module, version: MechSense.version, result });
}

function ng(res, module, error, status = 400) {
  return res.status(status).json({ ok: false, module, version: MechSense.version, error });
}

function formatSpring(raw) {
  return {
    input:        { d: raw.d, D: raw.D, Na: raw.Na, P: raw.P, mat: raw.mat },
    material:     { G: raw.G, sigmaB: raw.sigmaB },
    coefficients: { C: raw.C, K: raw.K },
    mechanics:    { k: raw.k, delta: raw.delta, tau: raw.tau, ratio: raw.ratio, Lc: raw.Lc },
    geometry:     { Do: raw.Do, Di: raw.Di, Nt: raw.Nt },
    judgment:     { status: raw.status, isSafe: raw.isSafe, stressOK: raw.stressOK, cRange: raw.cRange, warnings: raw.warnings },
  };
}

function formatBolt(raw) {
  return {
    input:   { d: raw.d, grade: raw.grade, partMat: raw.partMat, mu: raw.mu, sf: raw.sf, dep: raw.dep },
    torque:  { K: raw.K, Fy: raw.Fy, T_lim: raw.T_lim, T_jis: raw.T_jis, T_rec: raw.T_rec, T_range: raw.T_range },
    failure: { modes: raw.failModes, dominant: raw.dominant },
    judgment:{ isMaterialLimit: raw.isMaterialLimit, warnings: raw.warnings },
  };
}

function formatResonance(raw) {
  return {
    input:    { d: raw.d, D: raw.D, Na: raw.Na, mat: raw.mat, rpm: raw.rpm, mass: raw.mass },
    spring:   { k: raw.k, m_spring: raw.m_spring },
    resonance: {
      fn_surge:      raw.fn_surge,
      fn_surge_rpm:  raw.fn_surge_rpm,
      fn_modes:      (raw.fn_modes || []).map((fn, i) => ({ n: i+1, fn, rpm: fn * 60 })),
      f_safe_max:    raw.f_safe_max,
      fn_system:     raw.fn_system,
      fn_system_rpm: raw.fn_system_rpm,
      f_op:          raw.f_op,
      ratio_surge:   raw.ratio_surge,
    },
    judgment: { status: raw.status, warnings: raw.warnings },
  };
}

// ─── エンドポイント ────────────────────────────────────────

// GET /api/v1/health
app.get('/api/v1/health', (req, res) => {
  res.json({
    ok: true,
    service:   'mechsense-api',
    version:   MechSense.version,
    timestamp: new Date().toISOString(),
  });
});

// GET /api/v1/materials/spring
app.get('/api/v1/materials/spring', (req, res) => {
  const materials = Object.entries(MechSense.Spring.MATERIALS).map(([key, m]) => ({
    key,
    name: m.name,
    jis:  m.jis,
    G:    m.G,
  }));
  res.json({ ok: true, materials });
});

// GET /api/v1/bolts
app.get('/api/v1/bolts', (req, res) => {
  const bolts = Object.entries(MechSense.Bolt.BOLTS).map(([d, b]) => ({
    d: Number(d), ...b
  }));
  res.json({ ok: true, bolts });
});

// POST /api/v1/spring/calc
app.post('/api/v1/spring/calc', (req, res) => {
  const { d, D, Na, P, mat } = req.body || {};
  if (d == null || D == null || Na == null || P == null || !mat)
    return ng(res, 'Spring', 'd, D, Na, P, mat は必須です');

  const raw = MechSense.Spring.calc({ d: +d, D: +D, Na: +Na, P: +P, mat });
  if (raw.error) return ng(res, 'Spring', raw.error);
  return ok(res, 'Spring', formatSpring(raw));
});

// POST /api/v1/bolt/calc
app.post('/api/v1/bolt/calc', (req, res) => {
  const { d, grade, partMat, mu, sf, dep } = req.body || {};
  if (d == null || !grade || !partMat || !mu)
    return ng(res, 'Bolt', 'd, grade, partMat, mu は必須です');

  const params = { d: +d, grade, partMat, mu };
  if (sf  != null) params.sf  = +sf;
  if (dep != null) params.dep = +dep;

  const raw = MechSense.Bolt.calc(params);
  if (raw.error) return ng(res, 'Bolt', raw.error);
  return ok(res, 'Bolt', formatBolt(raw));
});

// POST /api/v1/resonance/calc
app.post('/api/v1/resonance/calc', (req, res) => {
  const { d, D, Na, mat, rpm, mass } = req.body || {};
  if (d == null || D == null || Na == null || !mat)
    return ng(res, 'Resonance', 'd, D, Na, mat は必須です');

  const params = { d: +d, D: +D, Na: +Na, mat };
  if (rpm  != null) params.rpm  = +rpm;
  if (mass != null) params.mass = +mass;

  const raw = MechSense.Resonance.calc(params);
  if (raw.error) return ng(res, 'Resonance', raw.error);
  return ok(res, 'Resonance', formatResonance(raw));
});

// POST /api/v1/combined/spring-resonance
app.post('/api/v1/combined/spring-resonance', (req, res) => {
  const { d, D, Na, P, mat, rpm, mass } = req.body || {};
  if (d == null || D == null || Na == null || P == null || !mat)
    return ng(res, 'Combined', 'd, D, Na, P, mat は必須です');

  const springRaw = MechSense.Spring.calc({ d: +d, D: +D, Na: +Na, P: +P, mat });
  if (springRaw.error) return ng(res, 'Combined', springRaw.error);

  const resParams = { d: +d, D: +D, Na: +Na, mat };
  if (rpm  != null) resParams.rpm  = +rpm;
  if (mass != null) resParams.mass = +mass;
  const resRaw = MechSense.Resonance.calc(resParams);
  if (resRaw.error) return ng(res, 'Combined', resRaw.error);

  res.json({
    ok:        true,
    module:    'Combined',
    version:   MechSense.version,
    spring:    formatSpring(springRaw),
    resonance: formatResonance(resRaw),
  });
});

// 404
app.use((req, res) => {
  res.status(404).json({ ok: false, error: `${req.method} ${req.path} は存在しません` });
});

// 起動
app.listen(PORT, () => {
  console.log(`mechsense-api v${MechSense.version} listening on http://localhost:${PORT}`);
  console.log('Endpoints:');
  console.log('  GET  /api/v1/health');
  console.log('  GET  /api/v1/materials/spring');
  console.log('  GET  /api/v1/bolts');
  console.log('  POST /api/v1/spring/calc');
  console.log('  POST /api/v1/bolt/calc');
  console.log('  POST /api/v1/resonance/calc');
  console.log('  POST /api/v1/combined/spring-resonance');
});

module.exports = app;

