/**
 * mechsense-worker  v1.0.0
 * MechSense 計算 REST API — Cloudflare Workers 版
 * 仕様: MECHSENSE_API_SPEC.md v1.2.0
 *
 * エントリポイント: wrangler.toml → main = "src/worker.js"
 * mechsense-core.js は wrangler(esbuild) がバンドル時に解決する
 */

import MechSense from '../../mechsense-core.js';

// ─── CORS / レスポンスヘルパー ────────────────────────────

function corsHeaders(origin) {
  return {
    'Access-Control-Allow-Origin':  origin,
    'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
  };
}

function jsonResponse(body, status = 200, origin = '*') {
  return new Response(JSON.stringify(body), {
    status,
    headers: { 'Content-Type': 'application/json', ...corsHeaders(origin) },
  });
}

function ok(module, result, origin) {
  return jsonResponse({ ok: true, module, version: MechSense.version, result }, 200, origin);
}

function ng(module, error, origin, status = 400) {
  return jsonResponse({ ok: false, module, version: MechSense.version, error }, status, origin);
}

// ─── フォーマッター（server.js と同一） ──────────────────

function formatSpring(raw) {
  return {
    input:        { d: raw.d, D: raw.D, Na: raw.Na, P: raw.P, mat: raw.mat },
    material:     { G: raw.G, sigmaB: raw.sigmaB },
    coefficients: { C: raw.C, K: raw.K },
    mechanics:    { k: raw.k, delta: raw.delta, tau: raw.tau, ratio: raw.ratio, Lc: raw.Lc },
    geometry:     { Do: raw.Do, Di: raw.Di, Nt: raw.Nt },
    judgment:     { status: raw.status, isSafe: raw.isSafe, stressOK: raw.stressOK, cRange: raw.cRange, warnings: raw.warnings },
  };
}

function formatBolt(raw) {
  return {
    input:    { d: raw.d, grade: raw.grade, partMat: raw.partMat, mu: raw.mu, sf: raw.sf, dep: raw.dep },
    torque:   { K: raw.K, Fy: raw.Fy, T_lim: raw.T_lim, T_jis: raw.T_jis, T_rec: raw.T_rec, T_range: raw.T_range },
    failure:  { modes: raw.failModes, dominant: raw.dominant },
    judgment: { isMaterialLimit: raw.isMaterialLimit, warnings: raw.warnings },
  };
}

function formatResonance(raw) {
  return {
    input:    { d: raw.d, D: raw.D, Na: raw.Na, mat: raw.mat, rpm: raw.rpm, mass: raw.mass },
    spring:   { k: raw.k, m_spring: raw.m_spring },
    resonance: {
      fn_surge:      raw.fn_surge,
      fn_surge_rpm:  raw.fn_surge_rpm,
      fn_modes:      (raw.fn_modes || []).map((fn, i) => ({ n: i + 1, fn, rpm: fn * 60 })),
      f_safe_max:    raw.f_safe_max,
      fn_system:     raw.fn_system,
      fn_system_rpm: raw.fn_system_rpm,
      f_op:          raw.f_op,
      ratio_surge:   raw.ratio_surge,
    },
    judgment: { status: raw.status, warnings: raw.warnings },
  };
}

// ─── ルーティング ────────────────────────────────────────

async function handleRequest(request, env) {
  const origin = env?.CORS_ORIGIN ?? '*';
  const { method } = request;
  const { pathname: path } = new URL(request.url);

  // CORS preflight
  if (method === 'OPTIONS') {
    return new Response(null, { status: 204, headers: corsHeaders(origin) });
  }

  // GET /api/v1/health
  if (method === 'GET' && path === '/api/v1/health') {
    return jsonResponse({
      ok:        true,
      service:   'mechsense-api',
      version:   MechSense.version,
      timestamp: new Date().toISOString(),
    }, 200, origin);
  }

  // GET /api/v1/materials/spring
  if (method === 'GET' && path === '/api/v1/materials/spring') {
    const materials = Object.entries(MechSense.Spring.MATERIALS).map(([key, m]) => ({
      key, name: m.name, jis: m.jis, G: m.G,
    }));
