    if (d == null || D == null || Na == null || P == null || !mat)
      return ng('Spring', 'd, D, Na, P, mat は必須です', origin);
    const raw = MechSense.Spring.calc({ d: +d, D: +D, Na: +Na, P: +P, mat });
    if (raw.error) return ng('Spring', raw.error, origin);
    return ok('Spring', formatSpring(raw), origin);
  }

  // POST /api/v1/bolt/calc
  if (method === 'POST' && path === '/api/v1/bolt/calc') {
    let body;
    try { body = await request.json(); } catch { return ng('Bolt', 'リクエストボディが不正です', origin); }
    const { d, grade, partMat, mu, sf, dep } = body;
    if (d == null || !grade || !partMat || !mu)
      return ng('Bolt', 'd, grade, partMat, mu は必須です', origin);
    const params = { d: +d, grade, partMat, mu };
    if (sf  != null) params.sf  = +sf;
    if (dep != null) params.dep = +dep;
    const raw = MechSense.Bolt.calc(params);
    if (raw.error) return ng('Bolt', raw.error, origin);
    return ok('Bolt', formatBolt(raw), origin);
  }

  // POST /api/v1/resonance/calc
  if (method === 'POST' && path === '/api/v1/resonance/calc') {
    let body;
    try { body = await request.json(); } catch { return ng('Resonance', 'リクエストボディが不正です', origin); }
    const { d, D, Na, mat, rpm, mass } = body;
    if (d == null || D == null || Na == null || !mat)
      return ng('Resonance', 'd, D, Na, mat は必須です', origin);
    const params = { d: +d, D: +D, Na: +Na, mat };
    if (rpm  != null) params.rpm  = +rpm;
    if (mass != null) params.mass = +mass;
    const raw = MechSense.Resonance.calc(params);
    if (raw.error) return ng('Resonance', raw.error, origin);
    return ok('Resonance', formatResonance(raw), origin);
  }

  // POST /api/v1/combined/spring-resonance
  if (method === 'POST' && path === '/api/v1/combined/spring-resonance') {
    let body;
    try { body = await request.json(); } catch { return ng('Combined', 'リクエストボディが不正です', origin); }
    const { d, D, Na, P, mat, rpm, mass } = body;
    if (d == null || D == null || Na == null || P == null || !mat)
      return ng('Combined', 'd, D, Na, P, mat は必須です', origin);
    const springRaw = MechSense.Spring.calc({ d: +d, D: +D, Na: +Na, P: +P, mat });
    if (springRaw.error) return ng('Combined', springRaw.error, origin);
    const resParams = { d: +d, D: +D, Na: +Na, mat };
    if (rpm  != null) resParams.rpm  = +rpm;
    if (mass != null) resParams.mass = +mass;
    const resRaw = MechSense.Resonance.calc(resParams);
    if (resRaw.error) return ng('Combined', resRaw.error, origin);
    return jsonResponse({
      ok:        true,
      module:    'Combined',
      version:   MechSense.version,
      spring:    formatSpring(springRaw),
      resonance: formatResonance(resRaw),
    }, 200, origin);
  }

  // 404
  return jsonResponse({ ok: false, error: `${method} ${path} は存在しません` }, 404, origin);
}

