/**
 * test-worker.js
 * `wrangler dev` が http://localhost:8787 で起動している状態で実行するテスト
 *
 * 使い方:
 *   ターミナル1: npm run dev   (wrangler dev)
 *   ターミナル2: npm test
 */

'use strict';

const BASE = process.env.BASE_URL || 'http://localhost:8787';
let pass = 0;
let fail = 0;

async function test(name, fn) {
  try {
    await fn();
    console.log(`  ✅ ${name}`);
    pass++;
  } catch (e) {
    console.error(`  ❌ ${name}: ${e.message}`);
    fail++;
  }
}

function assert(cond, msg) {
  if (!cond) throw new Error(msg ?? 'assertion failed');
}

async function getJson(path) {
  const r = await fetch(`${BASE}${path}`);
  return { status: r.status, body: await r.json() };
}

async function postJson(path, data) {
  const r = await fetch(`${BASE}${path}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(data),
  });
  return { status: r.status, body: await r.json() };
}

async function main() {
  console.log(`\nmechsense-worker テスト → ${BASE}\n`);

  // ── GET /health ──────────────────────────────────────
  console.log('GET /api/v1/health');

  await test('ok=true かつ service=mechsense-api', async () => {
    const { body } = await getJson('/api/v1/health');
    assert(body.ok === true);
    assert(body.service === 'mechsense-api');
  });

  await test('version フィールドが存在する', async () => {
    const { body } = await getJson('/api/v1/health');
    assert(typeof body.version === 'string' && body.version.length > 0);
  });

  await test('timestamp が ISO 8601 形式', async () => {
    const { body } = await getJson('/api/v1/health');
    assert(!isNaN(Date.parse(body.timestamp)));
  });

  // ── GET /materials/spring ────────────────────────────
  console.log('\nGET /api/v1/materials/spring');

  await test('6 材料が返る', async () => {
    const { body } = await getJson('/api/v1/materials/spring');
    assert(Array.isArray(body.materials));
    assert(body.materials.length === 6);
  });

  await test('SW-B が含まれる', async () => {
    const { body } = await getJson('/api/v1/materials/spring');
    assert(body.materials.some(m => m.key === 'SW-B'));
  });

  // ── GET /bolts ───────────────────────────────────────
  console.log('\nGET /api/v1/bolts');

  await test('複数ボルトサイズが返る', async () => {
    const { body } = await getJson('/api/v1/bolts');
    assert(Array.isArray(body.bolts) && body.bolts.length > 5);
  });

  // ── POST /spring/calc ────────────────────────────────
  console.log('\nPOST /api/v1/spring/calc');

  await test('基本例1: τ/σB ≈ 0.1945（SW-B d=2 D=15 Na=5 P=50）', async () => {
    const { body } = await postJson('/api/v1/spring/calc', { d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B' });
    assert(body.ok === true);
    const r = body.result.mechanics.ratio;
    assert(Math.abs(r - 0.1945) < 0.001, `ratio=${r}`);
  });

  await test('ばね定数 k ≈ 9.304 N/mm', async () => {
    const { body } = await postJson('/api/v1/spring/calc', { d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B' });
    const k = body.result.mechanics.k;
    assert(Math.abs(k - 9.3037) < 0.01, `k=${k}`);
  });

  await test('応力超過 NG を正しく検出', async () => {
    const { body } = await postJson('/api/v1/spring/calc', { d: 1, D: 15, Na: 5, P: 200, mat: 'SW-B' });
    assert(body.ok === true);
    assert(body.result.judgment.status === 'NG_STRESS');
    assert(body.result.judgment.isSafe === false);
  });

  await test('必須欠如 → HTTP 400', async () => {
    const { status, body } = await postJson('/api/v1/spring/calc', { d: 2, D: 15 });
    assert(status === 400);
    assert(body.ok === false);
  });

  await test('不正 mat → エラー', async () => {
    const { status, body } = await postJson('/api/v1/spring/calc', { d: 2, D: 15, Na: 5, P: 50, mat: 'INVALID' });
    assert(status === 400 || body.ok === false);
  });

  // ── POST /bolt/calc ──────────────────────────────────
  console.log('\nPOST /api/v1/bolt/calc');

  await test('M10 / 10.9 / 鋼 / 乾燥: T_lim ≈ 94.31 N·m', async () => {
    const { body } = await postJson('/api/v1/bolt/calc', { d: 10, grade: '10.9', partMat: '鋼', mu: 0.15 });
    assert(body.ok === true);
    const T = body.result.torque.T_lim;
    assert(Math.abs(T - 94.31) < 1.0, `T_lim=${T}`);
  });

  await test('M8 / 8.8 / アルミ / 潤滑: isMaterialLimit=true', async () => {
    const { body } = await postJson('/api/v1/bolt/calc', { d: 8, grade: '8.8', partMat: 'アルミ', mu: 0.12 });
    assert(body.ok === true);
    assert(body.result.judgment.isMaterialLimit === true);
  });

  await test('必須欠如 → HTTP 400', async () => {
    const { status } = await postJson('/api/v1/bolt/calc', { d: 10 });
    assert(status === 400);
  });

  // ── POST /resonance/calc ─────────────────────────────
  console.log('\nPOST /api/v1/resonance/calc');

  await test('基準: fn_surge ≈ 895 Hz（SW-B d=2 D=15 Na=5）', async () => {
    const { body } = await postJson('/api/v1/resonance/calc', { d: 2, D: 15, Na: 5, mat: 'SW-B' });
    assert(body.ok === true);
    const fn = body.result.resonance.fn_surge;
    assert(Math.abs(fn - 895) < 5, `fn_surge=${fn}`);
  });

  await test('SAFE 判定（rpm=3000, ratio << 65%）', async () => {
    const { body } = await postJson('/api/v1/resonance/calc', { d: 2, D: 15, Na: 5, mat: 'SW-B', rpm: 3000 });
    assert(body.result.judgment.status === 'SAFE');
  });

  await test('fn_modes が 4 要素の配列', async () => {
    const { body } = await postJson('/api/v1/resonance/calc', { d: 2, D: 15, Na: 5, mat: 'SW-B' });
    assert(Array.isArray(body.result.resonance.fn_modes));
    assert(body.result.resonance.fn_modes.length === 4);
  });

  // ── POST /combined/spring-resonance ─────────────────
  console.log('\nPOST /api/v1/combined/spring-resonance');

  await test('spring + resonance の両フィールドが返る', async () => {
    const { body } = await postJson('/api/v1/combined/spring-resonance', {
      d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B', rpm: 3000,
    });
    assert(body.ok === true);
    assert(body.spring != null);
    assert(body.resonance != null);
  });

  await test('spring.judgment.status が OK', async () => {
    const { body } = await postJson('/api/v1/combined/spring-resonance', {
      d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B',
    });
    assert(body.spring.judgment.status === 'OK');
  });

  // ── 404 ─────────────────────────────────────────────
  console.log('\n404 ハンドリング');

  await test('未知パス → 404 + ok=false', async () => {
    const { status, body } = await getJson('/api/v1/unknown');
    assert(status === 404);
    assert(body.ok === false);
  });

  await test('POST に GET → 404', async () => {
    const { status } = await getJson('/api/v1/spring/calc');
    assert(status === 404);
  });

  // ── CORS ─────────────────────────────────────────────
  console.log('\nCORS preflight');

  await test('OPTIONS → 204', async () => {
    const r = await fetch(`${BASE}/api/v1/spring/calc`, { method: 'OPTIONS' });
    assert(r.status === 204);
    assert(r.headers.get('Access-Control-Allow-Origin') != null);
  });

  // ── 結果 ──────────────────────────────────────────────
  console.log(`\n${'─'.repeat(40)}`);
  console.log(`結果: ${pass} PASS / ${fail} FAIL`);
  if (fail > 0) process.exit(1);
}

main().catch(e => { console.error(e); process.exit(1); });

