  assert('isSafe=false', spNG.body.result.judgment.isSafe === false);

  // ばね計算（バリデーションエラー）
  console.log('\n--- POST /spring/calc (必須欠如) ---');
  const spErr = await post('/spring/calc', { d: 2 });
  assert('status 400', spErr.status === 400);
  assert('ok=false', spErr.body.ok === false);
  assert('error メッセージあり', typeof spErr.body.error === 'string');

  // ボルト計算（正常）
  console.log('\n--- POST /bolt/calc (M10 10.9 steel dry) ---');
  const bo = await post('/bolt/calc', { d: 10, grade: '10.9', partMat: 'steel', mu: 'dry' });
  assert('status 200', bo.status === 200);
  assert('ok=true', bo.body.ok === true);
  assert('T_lim≈94.31', Math.abs(bo.body.result.torque.T_lim - 94.31) < 0.1);
  assert('K≈0.2032', Math.abs(bo.body.result.torque.K - 0.2032) < 0.001);

  // ボルト計算（軟質材制限）
  console.log('\n--- POST /bolt/calc (M8 8.8 aluminum lube) ---');
  const boAl = await post('/bolt/calc', { d: 8, grade: '8.8', partMat: 'aluminum', mu: 'lube' });
  assert('status 200', boAl.status === 200);
  // 注: 鋼の場合は isMaterialLimit=false が正常。アルミのログは結果確認のみ
  assert('ok=true', boAl.body.ok === true);

  // 共振計算（SAFE）
  console.log('\n--- POST /resonance/calc (SW-B d=2 D=15 Na=5 rpm=3000) ---');
  const re = await post('/resonance/calc', { d: 2, D: 15, Na: 5, mat: 'SW-B', rpm: 3000 });
  assert('status 200', re.status === 200);
  assert('fn_surge≈894.7', Math.abs(re.body.result.resonance.fn_surge - 894.7) < 1);
  assert('SAFE 判定', re.body.result.judgment.status === 'SAFE');
  assert('4次固有振動数', re.body.result.resonance.fn_modes.length === 4);

  // combined エンドポイント
  console.log('\n--- POST /combined/spring-resonance ---');
  const co = await post('/combined/spring-resonance', { d: 2, D: 15, Na: 5, P: 50, mat: 'SW-B', rpm: 3000 });
  assert('status 200', co.status === 200);
  assert('spring.OK', co.body.spring.judgment.status === 'OK');
  assert('resonance.SAFE', co.body.resonance.judgment.status === 'SAFE');
  assert('module=Combined', co.body.module === 'Combined');

  // 404
  console.log('\n--- 404 ハンドリング ---');
  const nf = await get('/nonexistent');
  assert('status 404', nf.status === 404);
  assert('ok=false', nf.body.ok === false);

  // 結果
  console.log(`\n${'='.repeat(40)}`);
  console.log(`結果: ${pass} PASS / ${fail} FAIL`);
  if (fail > 0) process.exit(1);
}

// サーバー起動待ち後にテスト実行
setTimeout(run, 500).unref();
// server.js を require してポート 3000 でリッスン開始
require('./server.js');

